import { useEffect, useMemo, useState } from "react";
import DriverSidebar from "../../components/driver/DriverSidebar";
import DriverTopbar from "../../components/driver/DriverTopbar";
import { useAuth } from "../../context/AuthContext";
import { apiRequest } from "../../api/client";
import "../../styles/auth.css";
import "../../styles/global.css";

export default function DriverDashboardPage() {
  const { user } = useAuth();

  const [history, setHistory] = useState([]);
  const [requests, setRequests] = useState([]);
  const [loading, setLoading] = useState(true);
  const [busyTripId, setBusyTripId] = useState(null);

  const loadData = async () => {
    if (!user?.id) return;
    try {
      setLoading(true);
      const [historyRes, reqRes] = await Promise.all([
        apiRequest(`/driver/trips/history?driverId=${user.id}`, { method: "GET" }),
        apiRequest(`/driver/trips/requests`, { method: "GET" }),
      ]);

      setHistory(historyRes?.trips || []);
      setRequests(reqRes?.trips || []);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, [user?.id]);

  const stats = useMemo(() => {
    const total = history.length;
    const completed = history.filter((t) => t.status === "completed").length;
    const active = history.filter((t) => ["accepted", "in_progress"].includes(t.status)).length;
    const earnings = history.reduce((acc, t) => acc + Number(t.earnings || 0), 0);
    return { total, completed, active, earnings: earnings.toFixed(2) };
  }, [history]);

  const acceptTrip = async (tripId) => {
    try {
      setBusyTripId(tripId);
      await apiRequest(`/driver/trips/${tripId}/accept`, {
        method: "POST",
        body: { driverId: user.id, eta: "6 min", distance: "3.2 km", fare: 45 },
      });
      await loadData();
    } finally {
      setBusyTripId(null);
    }
  };

  return (
    <div className="shell">
      <DriverSidebar />
      <div className="main">
        <DriverTopbar title="Driver Dashboard" subtitle="Trips, requests and earnings" />

        <div className="history-summary-grid">
          <div className="history-stat-card"><div className="history-stat-label">Total Trips</div><div className="history-stat-value">{stats.total}</div></div>
          <div className="history-stat-card"><div className="history-stat-label">Completed</div><div className="history-stat-value">{stats.completed}</div></div>
          <div className="history-stat-card"><div className="history-stat-label">Active</div><div className="history-stat-value">{stats.active}</div></div>
          <div className="history-stat-card"><div className="history-stat-label">Earnings</div><div className="history-stat-value">R{stats.earnings}</div></div>
        </div>

        <div className="card" style={{ marginBottom: 12 }}>
          <h3>Available Requests</h3>
          {loading ? <p>Loading...</p> : requests.length === 0 ? <p>No trip requests.</p> : (
            <div id="drivers-list">
              {requests.map((t) => (
                <div className="history-card" key={t.id}>
                  <div className="history-route">{t.pickup} → {t.destination}</div>
                  <div className="history-sub">Passenger: {t.passengerName} · {t.requestedAt}</div>
                  <button
                    className="btn btn-p btn-sm"
                    onClick={() => acceptTrip(t.id)}
                    disabled={busyTripId === t.id}
                    style={{ marginTop: 10 }}
                  >
                    {busyTripId === t.id ? "Accepting..." : "Accept Trip"}
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>

        <div className="card">
          <h3>Recent Trips</h3>
          {loading ? <p>Loading...</p> : history.length === 0 ? <p>No trips yet.</p> : (
            <div id="drivers-list">
              {history.slice(0, 5).map((t) => (
                <div className="history-card" key={t.id}>
                  <div className="history-head">
                    <div>
                      <div className="history-route">{t.pickup} → {t.destination}</div>
                      <div className="history-sub">Passenger: {t.passengerName} · {t.date}</div>
                    </div>
                    <span className={`history-status status-${t.status || "pending"}`}>{t.status}</span>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
